{"method_body":"{
  area := length * width;
  perimeter := 2.0 * (length + width);

  var s := (length * length) + (width * width);
  assert 0.0 <= s;
  assert exists d: real :: d * d == s;
  diagonal :| diagonal * diagonal == s;
  assert (diagonal * diagonal) - s == 0.0;
}"}

{"method_body":"{
  area := length * width;
  perimeter := 2.0 * (length + width);

  var s := (length * length) + (width * width);
  assert 0.0 <= s;
  assert exists d: real {:trigger d in {d}} :: d in {d} && d * d == s;
  diagonal :| diagonal in {diagonal} && diagonal * diagonal == s;
  assert (diagonal * diagonal) - s == 0.0;
  assert -0.01 < 0.0 < 0.01;
}"}

{"method_body":"{
  area := length * width;
  perimeter := 2.0 * (length + width);

  var s := (length * length) + (width * width);
  assert 0.0 <= length * length;
  assert 0.0 <= width * width;
  assert 0.0 <= s;

  var triggerSet: set<real> := {};
  assert exists d: real {:trigger d in triggerSet} :: (d in triggerSet || !(d in triggerSet)) && d * d == s;
  diagonal :| (diagonal in triggerSet || !(diagonal in triggerSet)) && diagonal * diagonal == s;

  assert diagonal * diagonal == s;
  assert (diagonal * diagonal) - s == 0.0;
  assert -0.01 < 0.0 < 0.01;
}"}

